  ('pukao-1fb53453-moex-00327', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '若獨占廠商的邊際生產成本為零，且可對兩群不同之消費者採取三級差別訂價，其最適之訂價策略為？', '["對需求彈性大者訂價於彈性小於1處，對需求彈性小者訂價於彈性大於1處", "對需求彈性小者訂價於彈性小於1處，對需求彈性大者訂價於彈性大於1處", "對需求彈性較大者訂價於彈性為1處，對需求彈性較小者訂價於彈性為1處", "對需求彈性大者訂價於彈性大於1處，對需求彈性小者訂價於彈性大於1處"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "b925101c356c", "answer_pdf_sha1": "e7ac1067ab7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00328', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '下列何者為獨占性競爭市場的特性？', '["廠商長期利潤為零", "廠商進出市場不易", "廠商是價格接受者", "廠商生產同質產品"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "b925101c356c", "answer_pdf_sha1": "e7ac1067ab7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00329', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '政府在 2020年因應疫情造成的經濟衰弱所發行的三倍券，在其他條件不變下，有關此政策對於總合供給 與總合需求的直接影響，下列敘述何者正確？', '["使總合供給右移", "使總合供給左移", "使總合需求右移", "使總合需求左移"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "b925101c356c", "answer_pdf_sha1": "e7ac1067ab7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00330', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '2021年初臺灣股市熱絡，熱錢不斷湧入，中央銀行若要維持臺幣對美元的匯率不變，外匯市場應該採取何 種措施？對外匯存底有何影響？', '["買進美金，外匯存底上升", "賣出美金，外匯存底上升", "買進美金，外匯存底下降", "賣出美金，外匯存底下降"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "b925101c356c", "answer_pdf_sha1": "e7ac1067ab7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00331', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '某位大學生畢業後有X、Y、Z三個工作機會，給定其他條件一樣，X的薪水最高，Y的薪水次之，Z的薪 水最低。根據前述資訊，請問下列敘述何者正確？', '["選擇X的機會成本高於選擇Y的機會成本", "選擇Z的機會成本高於選擇Y的機會成本", "選擇X的機會成本高於選擇Z的機會成本", "選擇Y的機會成本等於選擇Z的機會成本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "b925101c356c", "answer_pdf_sha1": "e7ac1067ab7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00332', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '新冠肺炎（COVID-19）疫情爆發後，口罩需求增加，又生產口罩所投入的原物料價格上升，假設口罩市場 為完全競爭，在給定其他條件不變下，請問下列關於口罩市場均衡變動之敘述何者正確？', '["均衡交易價格與數量均上升", "均衡交易數量下降，均衡交易價格變動方向不確定", "均衡交易價格上升，均衡交易數量下降", "均衡交易價格上升，均衡交易數量變動方向不確定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "b925101c356c", "answer_pdf_sha1": "e7ac1067ab7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00333', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '假設政府決定對汽油課徵每公升1元的稅，以降低汽油的使用量。在給定其他條件相同下，當消費者對於 汽油的需求變得較有彈性時，下列敘述何者正確？', '["消費者稅額負擔比例變低，課稅對於降低汽油使用量之效果較為顯著", "消費者稅額負擔比例不變，課稅對於降低汽油使用量之效果較為顯著", "消費者稅額負擔比例變高，課稅對於降低汽油使用量之效果較不顯著", "消費者稅額負擔比例變低，課稅對於降低汽油使用量之效果較不顯著"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "b925101c356c", "answer_pdf_sha1": "e7ac1067ab7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00334', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '某消費者有100元預算，用於購買蘋果與橘子，現在蘋果價格為6元，橘子價格為12元，請問下列何者 會讓消費者的預算線往外移？', '["預算變為200元，蘋果價格變為12元，橘子價格變為24元", "預算變為50元，蘋果價格變為2元，橘子價格變為4元", "預算維持100元，蘋果價格變為8元，橘子價格維持12元", "預算變為300元，蘋果價格變為24元，橘子價格變為48元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "b925101c356c", "answer_pdf_sha1": "e7ac1067ab7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00335', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '某甲消費X與Y兩種產品，兩產品消費量以(Qx,Qy)表示，若(3,3)、(4,3)及(3,5)均位於同一條無異曲線上， 則下列敘述何者正確？', '["X與Y為完全替代品，替代彈性無窮大", "X與Y為完全互補品，替代彈性無窮大", "X與Y為完全替代品，替代彈性趨近於零", "X與Y為完全互補品，替代彈性趨近於零"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "b925101c356c", "answer_pdf_sha1": "e7ac1067ab7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('pukao-1fb53453-moex-00336', 'pukao-1fb53453', 'pukao-1fb53453-moex-110-bacbaae8', 'sub-pukao-1fb53453-04', NULL, 'single_choice', '某追求利潤極大的完全競爭商店，因受新冠肺炎（COVID-19）疫情影響導致業績下滑並有虧損發生，但仍 決定短期繼續營業。請問關於該商店營業量所對應的邊際成本，下列敘述何者正確？', '["高於產品價格，介於平均變動成本與平均總成本之間", "高於產品價格，小於平均變動成本", "等於產品價格，介於平均變動成本與平均總成本之間", "等於產品價格，小於平均變動成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:54+00:00", "source_pdf_sha1": "b925101c356c", "answer_pdf_sha1": "e7ac1067ab7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "418", "s": "1011", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要與財政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL)
